def get_user(user_id):
    oid = parse_object_id(user_id)
    if not oid:
        return jsonify({"error": "Invalid user_id"}), 400

    user = users_col.find_one({"_id": oid})
    if not user:
        return jsonify({"error": "User not found"}), 404

    return jsonify(serialize_doc(user)), 200


@app.route("/users/<user_id>", methods=["PUT", "PATCH"])
def update_user(user_id):
    oid = parse_object_id(user_id)
    if not oid:
        return jsonify({"error": "Invalid user_id"}), 400

    data = request.get_json(force=True) or {}
    allowed = ["name", "email", "bio", "avatar_url", "role", "settings"]
    update = {k: v for k, v in data.items() if k in allowed}

    if "email" in update:
        update["email"] = update["email"].lower().strip()

    if not update:
        return jsonify({"error": "No valid fields to update"}), 400

    update["updated_at"] = datetime.utcnow()

    try:
        result = users_col.update_one({"_id": oid}, {"$set": update})
    except Exception as e:
        return jsonify({"error": "Could not update user", "details": str(e)}), 400

    if result.matched_count == 0:
        return jsonify({"error": "User not found"}), 404

    user = users_col.find_one({"_id": oid})
    return jsonify(serialize_doc(user)), 200


