@app.route("/documents/query", methods=["POST"])
def advanced_query():
    data = request.get_json(force=True) or {}
    filter_query = data.get("filter", {})
    projection = data.get("projection")
    sort = data.get("sort", [("created_at", -1)])
    limit = int(data.get("limit", 20))
    skip = int(data.get("skip", 0))

    if "user_id" in filter_query and isinstance(filter_query["user_id"], str):
        oid = parse_object_id(filter_query["user_id"])
        if not oid:
            return jsonify({"error": "Invalid user_id in filter"}), 400
        filter_query["user_id"] = oid

    if projection is not None and not isinstance(projection, dict):
        return jsonify({"error": "projection must be a dict"}), 400

    cursor = documents_col.find(filter_query, projection)

    if sort:
        sort_spec = []
        for item in sort:
            if isinstance(item, (list, tuple)) and len(item) == 2:
                field, direction = item
                direction = DESCENDING if int(direction) < 0 else ASCENDING
                sort_spec.append((field, direction))
        if sort_spec:
            cursor = cursor.sort(sort_spec)

    docs = [serialize_doc(doc) for doc in cursor.skip(skip).limit(limit)]
    return jsonify({"count": len(docs), "documents": docs}), 200


@app.route("/analytics/aggregation", methods=["POST"])
def aggregation_pipeline():
    data = request.get_json(force=True) or {}
    pipeline = data.get("pipeline", [])

    if not isinstance(pipeline, list):
        return jsonify({"error": "pipeline must be a list"}), 400

    for stage in pipeline:
        if not isinstance(stage, dict):
            return jsonify({"error": "Each pipeline stage must be an object"}), 400

    try:
        results = list(documents_col.aggregate(pipeline))
    except Exception as e:
        return jsonify({"error": "Aggregation failed", "details": str(e)}), 400

    for item in results:
        if "_id" in item and isinstance(item["_id"], ObjectId):
            item["_id"] = str(item["_id"])
        if "user_id" in item and isinstance(item["user_id"], ObjectId):
            item["user_id"] = str(item["user_id"])
        for field in ("created_at", "updated_at"):
            if field in item and isinstance(item[field], datetime):
                item[field] = item[field].isoformat()

    return jsonify({"count": len(results), "results": results}), 200


@app.route("/analytics/document-count-by-user", methods=["GET"])
def document_count_by_user():
    pipeline = [
        {"$group": {"_id": "$user_id", "document_count": {"$sum": 1}}},
        {"$lookup": {
            "from": "users",
            "localField": "_id",
            "foreignField": "_id",
            "as": "user"
        }},
        {"$unwind": {"path": "$user", "preserveNullAndEmptyArrays": True}},
        {"$project": {
            "_id": 0,
            "user_id": "$_id",
            "document_count": 1,
            "user_name": "$user.name",
            "user_email": "$user.email"
        }},
        {"$sort": {"document_count": -1}}
    ]

    results = list(documents_col.aggregate(pipeline))
    for item in results:
        if "user_id" in item and isinstance(item["user_id"], ObjectId):
            item["user_id"] = str(item["user_id"])

    return jsonify({"count": len(results), "results": results}), 200


